<template>
  <div style="padding:20px;">
    <Spin fix v-if="loadingshow" >
      <Icon type="ios-loading" size=18 class="demo-spin-icon-load"></Icon>
      <div>正在加载....</div>
    </Spin>
    <div><h1>图书信息管理</h1></div><br/>
    <div style="width:250px;float:left">
      <Input type="text" v-model="IBSN" placeholder="请输入图书序列号" style="width:180px"/>
      <Button shape="circle" icon="ios-search" @click="search"></Button>
    </div>
    <Button type="primary"  @click="insertWindowopen()" style="float:right">添加书籍</Button><br/><br/><br/>
    <Table stripe :columns="columns1" :data="dataview"></Table><br/><br/><br/>
    <Page :total="pagedata.count"
          :current="pagedata.currentPage"
          :page-size="pagedata.pageSize"
          show-elevator
          show-total
          @on-change="handlePage"></Page>
    <!--添加书籍弹窗-->
    <el-dialog title="添加书籍" :visible.sync="insertVisible"  width="700px">
      <el-form :model="insertform" >
        <el-form-item label="序列号" :label-width="formLabelWidth" >
        <el-input v-model="insertform.IBSN"  autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="书籍名称" :label-width="formLabelWidth">
          <el-input v-model="insertform.bookname" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="书籍作者" :label-width="formLabelWidth">
          <el-input v-model="insertform.author" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="书籍简介" :label-width="formLabelWidth">
        <el-input v-model="insertform.describe" autocomplete="off"></el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="insertVisible = false">取 消</el-button >
        <el-button type="primary" @click="insertbook">确 定</el-button>
      </div>
    </el-dialog>
    <!--更新书籍弹窗-->
    <el-dialog  title="书籍信息修改" :visible.sync="updateVisible"  width="700px">
      <el-form :model="updateform" >
        <el-form-item label="序列号" :label-width="formLabelWidth">
          <el-input v-model="updateform.IBSN" autocomplete="off" readonly=""></el-input>
        </el-form-item>
        <el-form-item label="书籍名称" :label-width="formLabelWidth" >
          <el-input v-model="updateform.bookname"  autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="作者" :label-width="formLabelWidth">
        <el-input v-model="updateform.author" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="简介" :label-width="formLabelWidth">
          <el-input v-model="updateform.describe" autocomplete="off"></el-input>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="updateVisible = false">取 消</el-button>
        <el-button type="primary" @click="updatebook">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
  import  api from '../../API/api'
  export default {
    name: "book",
    data () {
      return {
        IBSN:'',                    //前端获取数据
        bookInfoObj: {},            //后端返回的数据储存在这里
        insertform: {},             //添加人员的model
        updateform: {},             //更新人员的model
        insertVisible: false,       //添加人员弹框默认隐藏
        updateVisible: false,       //更新用户弹框默认隐藏
        formLabelWidth   : '80px',   //弹出框的大小
        pagedata   :{},              //后台发送的分页数据包含count数据总条数;totalPages页面总数;pageSize单页面数据量;currentPage当前页面的页数
        sendpage:"1",                //初始的发送页
        loadingshow: false,          //加载动画默认关闭
        dataview:[] ,      //将userInfoObj中的内容重新赋给dataview并显示在表格
        columns1:[
          {
            title: '序号',
            type  : 'index'
          },
          {
            title: '书籍序列号',
            key  : 'IBSN'
          },
          {
            title: '书籍名称',
            key  : 'bookname'
          },
          {
            title: '作者',
            key  : 'author'
          },
          {
            title: '简介',
            key  : 'describe'
          },
          {
            title : '操作',
            key   : 'action',
            width : 300,
            align : 'center',
            render: (h, params) => {
              return h('div', [
                h('Button', {
                  props: {
                    type: 'success',
                    size: 'large'
                  },
                  style: {
                    marginRight: '5px'
                  },
                  on: {
                    click: () => {
                      this.updateWindowopen(params.row)
                    }
                  }
                }, '编辑'),
                h('Button', {
                  props: {
                    type: 'error',
                    size: 'large'
                  },
                  on: {
                    click: () => {
                      this.deleteuser(params.row.IBSN)
                    }
                  }
                }, '删除')
              ]);
            }
          }

        ],                //定义表格列

      }
    },
    //查看所有书籍
    created:function(){
      this.selectallbook();
      this.loadingshow= true;    //开启进场动画
      setTimeout(() => {
        this.loadingshow= false; //关闭进场动画
      }, 1000);
    },
    methods: {
      //从UI组件的取值，获取当前页
      handlePage(value) {
        this.sendpage = value;
        this.selectallbook();
      },
      //查看所有书籍
      selectallbook: function(){
        this.$Loading.start();       //设置进度条开始数据加载
        let data = {
          currentPage : this.sendpage,
        };
        this.$http.post(api.apiConfig.book.selectbook,data)
          .then(res => {
            if (res.data.errno === 0) {
              // this.pagedata = res.data.data;//后端发送的分页信息
              // this.dataview = res.data.data.data;//用户信息保存在dataview中并显示
              setTimeout(() => {
                this.pagedata = res.data.data;//后端发送的分页信息
                this.dataview = res.data.data.data;//用户信息保存在dataview中并显示
                this.$Message.success("查询图书成功");
                this.$Loading.finish();      //数据加载完成
              }, 1000);
            } else {
              this.$Loading.error();       //数据加载错误
              this.$Message.error("查询图书失败")
            }
          }).catch(err => {
          this.$Loading.error();       //数据加载错误
          this.$Message.error("服务器错误")
        })
      },
      //删除书籍
      deleteuser(code){
        console.log('code',code);
        this.$Modal.confirm({
          title  : '确认删除书籍？',
          content: '<p>删除后将无法撤回</p>',
          onOk   : () => {
            // this.$http.delete(api.apiConfig.user.remove,{
            //   params:{account: code}
            // })
            let data = {
              IBSN : code
            };
            this.$http.post(api.apiConfig.book.deletebook,data)
              .then(res =>
              {
                console.log("res",res);
                if (res.data.errno === 0) {
                  this.sendpage= '1';
                  this.selectallbook();  //重新查询数据库
                  this.$Message.success("删除书籍成功");
                } else if(res.data.errno === 100) {
                  this.$Message.error("书籍不存在")
                } else if(res.data.errno === 505) {
                  this.$Message.error("缺少参数")
                }
              }).catch(err => {
              this.$Message.error("服务器错误")
            })
          },
          onCancel: () => {
          }
        });
      },
      //申请添加书籍
      insertWindowopen: function () {
        this.insertVisible = true;
      },
      //提交用户信息
      insertbook:function(){
        let data = {
          IBSN                 : this.insertform.IBSN,
          bookname             : this.insertform.bookname,
          author               : this.insertform.author,
          describe             : this.insertform.describe,
        };
        this.$http.post(api.apiConfig.book.addbook,data).then(
          res=>{
            console.log(res.data);
            if(res.data.errno===0){
              this.sendpage= '1';        //页码重置为1
              this.selectallbook();      //重新查询数据库
              this.insertform.IBSN = ''; //数据置空
              this.insertform.bookname = ''; //数据置空
              this.insertform.author = ''; //数据置空
              this.insertform.describe = ''; //数据置空
              this.insertVisible = false;  //关闭弹窗
              this.$Message.success('添加书籍成功');
            }else if(res.data.errno===300){
              this.$Message.warning('书籍已经存在！');
            }
          },
          err=>{
            console.log("服务器错误！");
          })
      },
      //申请更新用户
      updateWindowopen: function (editparams) {
        this.updateVisible = true;
        this.updateform    = editparams;//将原来信息显示在修改表格中
      },
      //提交更新信息
      updatebook: function () {
        let data = {
          IBSN                 : this.updateform.IBSN,
          bookname             : this.updateform.bookname,
          author               : this.updateform.author,
          describe             : this.updateform.describe,
        };
        this.$http.put(api.apiConfig.book.upbook,data).then(
          res=>{
            console.log(res,'返回')
            if(res.data.errno===0){
              this.updateVisible = false;  //关闭弹窗
              this.$Message.success('信息修改成功');
              this.sendpage = '1';    //页码重置
              this.selectallbook();    //重新查询
            }else if(res.data.errno===505){
              this.$Message.warning('缺少参数！');
              this.updateVisible = false;  //关闭弹窗
              this.sendpage = '1';    //页码重置
              this.selectallbook();    //重新查询
            }else if (res.data.errno===100){
              this.$Message.warning('书籍不存在！');
              this.updateVisible = false;  //关闭弹窗
              this.sendpage = '1';    //页码重置
              this.selectallbook();    //重新查询
            } else{
              this.$Message.warning('修改失败未知错误！');
              this.updateVisible = false;  //关闭弹窗
            }
          },
          err=>{
            console.log("服务器错误！");
          })
      },
      //查找指定书籍
      search(){
        let data = {
          IBSN : this.IBSN
        }
        this.$http.post(api.apiConfig.book.findbook,data)
          .then(res => {
            if (res.data.errno === 0) {
              this.bookInfoObj = res.data.data;
              console.log(res.data.data,'res.data.data')
              this.$Message.success("查找书籍成功");
              this.$Modal.info({
                title  : '书籍详情',
                content:
                  `书籍序列号：${this.bookInfoObj.IBSN}<br>
                    书籍名称：${this.bookInfoObj.bookname}<br>
                    书籍作者：${this.bookInfoObj.author}<br>
                    书籍简介：${this.bookInfoObj.describe}`
              })
            } else if (res.data.errno === 100){
              this.$Message.warning("书籍不存在")
            }else if(res.data.errno === 505){
              this.$Message.warning("缺少参数")
            }
          }).catch(err => {
          this.$Message.error("服务器错误")
        })
      },
    }
  }
</script>

<style scoped>

</style>



